import './Certificates.css';

const Certificates = () => {
  const certificates = [
    'Certificate 1: Description of the certificate.',
    'Certificate 2: Description of the certificate.',
    'Certificate 3: Description of the certificate.',
  ];

  return (
    <div className="certificates-container">
      <h1>Certificates</h1>
      <ul className="certificates-list">
        {certificates.map((certificate, index) => (
          <li key={index}>{certificate}</li>
        ))}
      </ul>
    </div>
  );
};

export default Certificates;
